386:     async fn run_loop(
387:         &mut self,
388:         tools: Option<&ToolRegistry>,
389:     ) -> Result<AgentOutput, AgentError> {
390:         const MAX_ITERATIONS: usize = 10;
391:         let mut accumulated_text = String::new();
392:         let tools_for_request = tools.map(ToolRegistry::to_openai_format_shared);
393: 
394:         for _ in 0..MAX_ITERATIONS {
395:             let mut messages = Vec::with_capacity(self.message_log.len() + 1);
396:             messages.push(OpenAiMessage::System {
397:                 content: self.config.system_prompt.clone(),
398:             });
399:             self.message_log.extend_api_format(&mut messages);
400: 
401:             let request = LlmRequest {
402:                 model: self.config.model.clone(),
403:                 messages,
404:                 tools: tools_for_request.clone(),
405:                 temperature: self.config.temperature,
406:                 max_tokens: self.config.max_tokens,
407:             };
408: 
409:             let response = self.llm.complete(request).await?;
410: 
411:             match response {
412:                 LlmResponse::Text(text) => {
413:                     accumulated_text.push_str(&text);
414:                     self.message_log.add_assistant(text);
415:                 }
416:                 LlmResponse::ToolCall { name, args } => {
417:                     if let Some(registry) = tools {
418:                         let result = registry.execute(&name, &args).await?;
419:                         self.message_log
420:                             .add_tool_result(name, format_tool_result_content(result));
421:                     }
422:                 }
423:                 LlmResponse::Done => break,
424:             }
425:         }
426: 
427:         Ok(AgentOutput::Text(accumulated_text))
428:     }
429: }
