41:     pub async fn connect(&self) -> Result<Arc<Session>, ZenohError> {
42:         let mut guard = self.session.write().await;
43:         if guard.is_some() {
44:             return Err(ZenohError::AlreadyConnected);
45:         }
46: 
47:         // Build bus config from ZenohConfig with fast accept timeout for quick operations
48:         let mut zenoh_config_json = serde_json::json!({
