183:     /// Execute multiple tools in parallel for batch operations
184:     /// Returns results in the same order as input requests
185:     pub async fn execute_batch(
186:         &self,
187:         requests: Vec<(String, serde_json::Value)>
188:     ) -> Vec<Result<serde_json::Value, ToolError>> {
189:         use futures::future::join_all;
190: 
191:         let futures: Vec<_> = requests
192:             .into_iter()
193:             .map(|(name, args)| {
194:                 let registry = self;
195:                 async move {
196:                     let tool = registry.tools.get(&name).cloned();
197:                     match tool {
198:                         Some(tool) => {
199:                             let schema = if let Some(cached) = registry.schema_cache.get(&name).map(|r| r.clone()) {
200:                                 cached
201:                             } else {
202:                                 let schema = tool.cached_schema();
203:                                 registry.schema_cache.insert(name.clone(), schema.clone());
204:                                 schema
205:                             };
206:                             if let Err(e) = super::validate_args(schema.as_ref(), &args) {
207:                                 Err(e)
208:                             } else {
209:                                 tool.execute(&args).await
210:                             }
211:                         }
212:                         None => Err(ToolError::NotFound(name)),
213:                     }
214:                 }
215:             })
216:             .collect();
217: 
218:         join_all(futures).await
219:     }
