41: 
42: impl McpClient {
43:     pub async fn spawn(command: &str, args: &[&str]) -> Result<Self, McpError> {
44:         let transport = StdioTransport::spawn(command, args).await?;
45:         Ok(Self {
46:             transport: Arc::new(Mutex::new(transport)),
47:             request_id: std::sync::atomic::AtomicU64::new(1),
48:             capabilities: std::sync::Mutex::new(None),
49:             recv_buffer: std::sync::Mutex::new(String::with_capacity(8192)),
50:         })
51:     }
52: 
53:     pub async fn initialize(&self) -> Result<ServerCapabilities, McpError> {
54:         let resp = self
55:             .call(
56:                 "initialize",
57:                 Some(serde_json::json!({
58:                     "protocolVersion": "2025-03-26",
59:                     "capabilities": {
60:                         "roots": { "listChanged": true },
61:                         "sampling": {}
62:                     },
63:                     "clientInfo": {
64:                         "name": "brainos-agent",
65:                         "version": "1.0.0"
66:                     }
67:                 })),
68:             )
69:             .await?;
70: 
71:         if let Some(error) = resp.error {
72:             return Err(McpError::InitFailed(error.message));
73:         }
74: 
75:         let capabilities = resp
76:             .result
77:             .as_ref()
78:             .and_then(|v| v.get("capabilities"))
79:             .cloned()
80:             .unwrap_or(serde_json::json!({"tools": false, "resources": false, "prompts": false}));
81: 
82:         let caps: ServerCapabilities = serde_json::from_value(capabilities)
83:             .map_err(|e| McpError::Protocol(e.to_string()))?;
84: 
85:         *self.capabilities.lock().unwrap() = Some(caps.clone());
86: 
87:         self.notify("notifications/initialized", None).await?;
