115:     fn build_request(&self, req: LlmRequest, stream: bool) -> OpenAiRequest {
116:         let mut messages = Vec::with_capacity(req.messages.len());
117:         for message in req.messages {
118:             let (role, content, tool_call_id) = match message {
119:                 OpenAiMessage::System { content } => ("system", content, None),
120:                 OpenAiMessage::User { content } => ("user", content, None),
121:                 OpenAiMessage::Assistant { content } => ("assistant", content, None),
122:                 OpenAiMessage::ToolResult { tool_call_id, content } => {
123:                     ("tool", content, Some(tool_call_id))
124:                 }
125:             };
126:             messages.push(OpenAiMessageJson {
127:                 role,
128:                 content,
129:                 tool_call_id,
130:             });
131:         }
132: 
133:         OpenAiRequest {
134:             model: req.model,
135:             messages,
136:             tools: req.tools.map(|tools| (*tools).clone()),
137:             temperature: req.temperature,
138:             max_tokens: req.max_tokens,
139:             stream,
140:         }
141:     }
