184:         if !response.status().is_success() {
185:             let status = response.status();
186:             let body = response.text().await.unwrap_or_default();
187:             return Err(LlmError::Http(format!("HTTP {}: {}", status, body)));
188:         }
189: 
190:         let body: OpenAiResponse = response.json().await.map_err(|e| LlmError::Parse(e.to_string()))?;
191: 
192:         let choice = body.choices.into_iter().next().ok_or_else(|| {
193:             LlmError::Parse("No choices in response".to_string())
194:         })?;
195: 
196:         if let Some(tool_calls) = choice.message.tool_calls {
197:             if let Some(tc) = tool_calls.into_iter().next() {
198:                 let args: serde_json::Value = serde_json::from_str(&tc.function.arguments)
199:                     .unwrap_or_else(|_| serde_json::json!({}));
200:                 return Ok(LlmResponse::ToolCall {
201:                     name: tc.function.name,
202:                     args,
203:                 });
204:             }
205:         }
