207:         if choice.finish_reason.as_deref() == Some("stop") {
208:             return Ok(LlmResponse::Done);
209:         }
210: 
211:         match choice.message.content {
212:             Some(content) => Ok(LlmResponse::Text(content)),
213:             None => Ok(LlmResponse::Done),
214:         }
