17: /// Discovery information published by RPC services.
18: #[derive(Debug, Clone, Serialize, Deserialize, rkyv::Archive, rkyv::Serialize, rkyv::Deserialize)]
19: pub struct DiscoveryInfo {
20: 	/// Topic prefix for the service (e.g., "rpc/my-service")
21: 	pub topic_prefix: String,
22: 	/// Name of the discovered service
23: 	pub service_name: String,
24: 	/// Service version (e.g., "1.0.0")
25: 	pub version: String,
26: 	/// Topic for health status publishing (e.g., "rpc/health/my-service")
27: 	pub health_topic: String,
28: }
29: 
30: impl DiscoveryInfo {
31: 	pub fn new(service_name: &str) -> Self {
32: 		let topic_prefix = format!("rpc/{}", service_name);
33: 		Self {
34: 			topic_prefix: topic_prefix.clone(),
35: 			service_name: service_name.to_string(),
36: 			version: "1.0.0".to_string(),
37: 			health_topic: format!("rpc/health/{}", service_name),
38: 		}
39: 	}
40: }
41: 
42: /// Service discovery via pub/sub.
43: ///
44: /// RpcService publishes its info on init. RpcDiscovery subscribes to
45: /// `rpc/services/*` and collects announcements within a timeout window.
46: pub struct RpcDiscovery {
47:     service_name: String,
48: }
49: 
50: impl RpcDiscovery {
51:     /// Create a discovery announcer for the given service name.
52:     ///
53:     /// After initialization with `init()`, the service info is published
54:     /// to `rpc/services/{service_name}`.
55:     pub fn announce(service_name: impl Into<String>) -> Self {
56:         Self {
57:             service_name: service_name.into(),
58:         }
59:     }
60: 
61:     /// Initialize and publish service info.
62:     ///
63:     /// Publishes DiscoveryInfo to `rpc/services/{service_name}`.
64:     pub async fn init(&mut self, session: Arc<Session>) -> Result<(), ZenohError> {
65:         let info = DiscoveryInfo::new(&self.service_name);
66:         let topic = format!("rpc/services/{}", self.service_name);
67:         let data = Codec
68:             .encode(&info)
69:             .map_err(|e| ZenohError::Serialization(e.to_string()))?;
70: 
71:         session
72:             .declare_publisher(&topic)
73:             .await?
74:             .put(data)
75:             .await
76:             .map_err(|e| ZenohError::Publisher(e.to_string()))?;
77: 
78:         Ok(())
79:     }
80: 
81:     /// Returns the service name.
82:     pub fn service_name(&self) -> &str {
83:         &self.service_name
84:     }
85: 
86:     /// Create a discovery query builder for finding services.
87:     pub fn discover(service_name: impl Into<String>) -> DiscoveryQueryBuilder {
88:         DiscoveryQueryBuilder::new(service_name)
89:     }
90: }
