100: /// Builder for discovery queries.
101: pub struct DiscoveryQueryBuilder {
102:     service_name: String,
103:     session: Option<Arc<Session>>,
104:     timeout: Duration,
105: }
106: 
107: impl DiscoveryQueryBuilder {
108:     fn new(service_name: impl Into<String>) -> Self {
109:         Self {
110:             service_name: service_name.into(),
111:             session: None,
112:             timeout: Duration::from_secs(2),
113:         }
114:     }
115: 
116:     pub fn session(mut self, session: Arc<Session>) -> Self {
117:         self.session = Some(session);
118:         self
119:     }
120: 
121:     pub fn timeout(mut self, timeout: Duration) -> Self {
122:         self.timeout = timeout;
123:         self
124:     }
125: 
126:     /// Query for the service by subscribing to `rpc/services/*` and
127:     /// collecting announcements within the timeout window.
128:     pub async fn query(self) -> Result<DiscoveryInfo, ZenohError> {
129:         let session = self.session.as_ref().ok_or(ZenohError::NotConnected)?;
130: 
131:         let topic = format!("rpc/services/{}", self.service_name);
132:         let mut subscriber = Subscriber::<DiscoveryInfo>::new(&topic);
133:         subscriber.init(session.clone()).await?;
134: 
135:         let deadline = tokio::time::Instant::now() + self.timeout;
136:         let mut last_seen: Option<DiscoveryInfo> = None;
137: 
138:         while tokio::time::Instant::now() < deadline {
139:             let remaining = deadline.saturating_duration_since(tokio::time::Instant::now());
140:             if remaining.is_zero() {
141:                 break;
142:             }
143: 		if let Some(info) = subscriber.recv_with_timeout(remaining).await {
144: 			if info.service_name == self.service_name {
145: 				return Ok(info);
146: 			}
147: 			last_seen = Some(info);
148: 		} else {
149: 			break;
150: 		}
151:         }
152: 
153:         if let Some(info) = last_seen {
154:             return Ok(info);
155:         }
156: 
157:         Err(ZenohError::Query(format!(
158:             "No discovery response for service: {}",
159:             self.service_name
160:         )))
161: 	}
162: }
