164: /// Registry for discovering all advertised services.
165: /// Subscribes to `rpc/services/**` and collects announcements within a timeout.
166: pub struct DiscoveryRegistry {
167: 	session: Option<Arc<Session>>,
168: 	timeout: Duration,
169: }
170: 
171: impl DiscoveryRegistry {
172: 	/// Create a new registry.
173: 	pub fn new() -> Self {
174: 		Self {
175: 			session: None,
176: 			timeout: Duration::from_secs(2),
177: 		}
178: 	}
179: 
180: 	/// Set the session.
181: 	pub fn session(mut self, session: Arc<Session>) -> Self {
182: 		self.session = Some(session);
183: 		self
184: 	}
185: 
186: 	/// Set the discovery timeout.
187: 	pub fn timeout(mut self, timeout: Duration) -> Self {
188: 		self.timeout = timeout;
189: 		self
190: 	}
191: 
192: 	/// Subscribe to `rpc/services/**` and collect all discovery announcements.
193: 	pub async fn list_services(&self) -> Result<Vec<DiscoveryInfo>, ZenohError> {
194: 		let session = self.session.as_ref().ok_or(ZenohError::NotConnected)?;
195: 		let topic = "rpc/services/**";
196: 		let mut subscriber = Subscriber::<DiscoveryInfo>::new(topic);
197: 		subscriber.init(session.clone()).await?;
198: 
199: 		let deadline = tokio::time::Instant::now() + self.timeout;
200: 		let mut services = Vec::new();
201: 
202: 		while tokio::time::Instant::now() < deadline {
203: 			let remaining = deadline.saturating_duration_since(tokio::time::Instant::now());
204: 			if remaining.is_zero() {
205: 				break;
206: 			}
207: 			if let Some(info) = subscriber.recv_with_timeout(remaining).await {
208: 				if !services.iter().any(|s: &DiscoveryInfo| s.service_name == info.service_name) {
209: 					services.push(info);
210: 				}
211: 			} else {
212: 				break;
213: 			}
214: 		}
215: 
216: 		Ok(services)
217: 	}
218: }
