现在我理解了工具调用的完整流程。让我为你展示几种调用工具的方式：

## 🔧 工具调用方式

### 方式一：直接通过 ToolRegistry 调用

```rust
use std::sync::Arc;
use agent::{ToolRegistry, FunctionTool, ToolError};

#[tokio::main]
async fn main() -> Result<(), ToolError> {
    // 1. 创建工具注册中心
    let mut registry = ToolRegistry::new();

    // 2. 注册本地函数工具
    let add_tool = FunctionTool::numeric(
        "add",
        "Add two numbers",
        2,  // 参数数量
        |args| {
            let a = args["a"].as_f64().ok_or_else(|| 
                ToolError::ExecutionFailed("a required".to_string()))?;
            let b = args["b"].as_f64().ok_or_else(|| 
                ToolError::ExecutionFailed("b required".to_string()))?;
            Ok(serde_json::json!(a + b))
        }
    );
    registry.register(Arc::new(add_tool))?;

    // 3. 直接调用工具
    let args = serde_json::json!({"a": 5.0, "b": 3.0});
    let result = registry.execute("add", &args).await?;
    println!("Result: {}", result);  // 输出: Result: 8.0

    Ok(())
}
```

### 方式二：通过 Agent 调用（LLM 自动决策）

```rust
use std::sync::Arc;
use agent::{Agent, AgentConfig, FunctionTool, ToolRegistry};
use agent::llm::OpenAiClient;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // 1. 创建 LLM 客户端
    let llm = Arc::new(OpenAiClient::new(
        "https://api.openai.com/v1".to_string(),
        std::env::var("OPENAI_API_KEY")?,
    ));

    // 2. 配置 Agent
    let config = AgentConfig {
        name: "calculator-agent".to_string(),
        model: "gpt-4o".to_string(),
        base_url: "https://api.openai.com/v1".to_string(),
        api_key: std::env::var("OPENAI_API_KEY")?,
        system_prompt: "You are a helpful calculator.".to_string(),
        temperature: 0.7,
        max_tokens: Some(1000),
        timeout_secs: 60,
    };

    // 3. 创建 Agent 并注册工具
    let mut agent = Agent::new(config, llm);

    // 注册工具
    agent.register_numeric_function(
        "add",
        "Add two numbers",
        2,
        |args| {
            let a = args["a"].as_f64().unwrap();
            let b = args["b"].as_f64().unwrap();
            Ok(serde_json::json!(a + b))
        }
    )?;

    // 4. 运行 Agent（LLM 会自动决定是否调用工具）
    let output = agent.run_with_tools("What is 15 + 27?", None).await?;
    println!("{:?}", output);

    Ok(())
}
```

### 方式三：使用 UnifiedToolRegistry 统一调用（多源工具）

```rust
use std::sync::Arc;
use agent::{
    UnifiedToolRegistry, FunctionTool, 
    ZenohRpcDiscovery, A2AToolDiscovery, A2AToolClient,
};
use zenoh::Session;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // 1. 连接 Zenoh
    let session = Arc::new(Session::open(zenoh::Config::default()).await?);

    // 2. 创建统一注册中心
    let mut registry = UnifiedToolRegistry::new()
        .with_zenoh_session(session.clone());

    // 3. 注册本地工具
    registry.register_local(Arc::new(FunctionTool::numeric(
        "local_add",
        "Local addition",
        2,
        |args| Ok(serde_json::json!(
            args["a"].as_f64().unwrap() + args["b"].as_f64().unwrap()
        ))
    )))?;

    // 4. 添加发现源（自动发现远程工具）
    registry.add_discovery_source(Arc::new(
        ZenohRpcDiscovery::new(session.clone())
            .service_prefix("agent/")
    ));

    registry.add_discovery_source(Arc::new(
        A2AToolDiscovery::new(session.clone())
            .capability("calculation")
    ));

    // 5. 执行发现并注册所有工具
    let registered = registry.discover_and_register_all().await?;
    println!("Discovered {} tools", registered.len());

    // 6. 调用本地工具
    let result = registry.execute(
        "local/add",  // namespace/tool_name
        &serde_json::json!({"a": 10.0, "b": 20.0})
    ).await?;
    println!("Local result: {}", result);

    // 7. 调用远程 RPC 工具
    let result = registry.execute(
        "rpc/calculator/multiply",  // 远程工具
        &serde_json::json!({"a": 5.0, "b": 6.0})
    ).await?;
    println!("RPC result: {}", result);

    // 8. 调用 A2A 远程 Agent 工具
    let result = registry.execute(
        "a2a/bob-agent/calculate",  // A2A 工具
        &serde_json::json!({"input": "15 + 27"})
    ).await?;
    println!("A2A result: {}", result);

    Ok(())
}
```

### 方式四：直接使用特定工具类型

```rust
use std::sync::Arc;
use agent::{A2AToolClient, BusToolClient, McpToolAdapter};
use agent::mcp::McpClient;
use agent::a2a::AgentIdentity;
use zenoh::Session;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let session = Arc::new(Session::open(zenoh::Config::default()).await?);

    // === RPC 工具调用 ===
    let rpc_tool = BusToolClient::new(
        session.clone(),
        "agent/bob/tools/add".to_string(),
        "add".to_string(),
    );
    let result = rpc_tool.execute(&serde_json::json!({"a": 1.0, "b": 2.0})).await?;
    println!("RPC: {}", result);

    // === MCP 工具调用 ===
    let mcp_client = McpClient::spawn("npx", &["-y", "@modelcontextprotocol/server-filesystem"]).await?;
    mcp_client.initialize().await?;

    let mcp_tool = McpToolAdapter::new(
        Arc::new(mcp_client),
        "read_file".to_string(),
        "Read a file".to_string(),
        serde_json::json!({"type": "object", "properties": {"path": {"type": "string"}}}),
    );
    let result = mcp_tool.execute(&serde_json::json!({"path": "/tmp/test.txt"})).await?;
    println!("MCP: {}", result);

    // === A2A 工具调用 ===
    let target_agent = AgentIdentity::new(
        "bob".to_string(),
        "Calculator Agent".to_string(),
        "1.0.0".to_string(),
    );

    let a2a_tool = A2AToolClient::new(
        session.clone(),
        target_agent,
        "calculate".to_string(),
        "Perform calculation on remote agent".to_string(),
        serde_json::json!({"type": "object", "properties": {"input": {"type": "string"}}}),
    );

    let result = a2a_tool.execute(&serde_json::json!({"input": "5 + 3"})).await?;
    println!("A2A: {}", result);

    Ok(())
}
```

